mapper.select:
SELECT s.* FROM subject s

    INNER JOIN subject_mapping m ON s.id = m.subject_id AND m.is_deleted = 0

WHERE s.is_deleted = 0

    AND m.category_id = #{categoryId}


    AND m.label_id = #{labelId}


    AND s.subject_name LIKE CONCAT('%', #{keyword}, '%')

ORDER BY s.id DESC
LIMIT #{offset}, #{limit}

SELECT COUNT(DISTINCT s.id) FROM subject s

    INNER JOIN subject_mapping m ON s.id = m.subject_id AND m.is_deleted = 0

WHERE s.is_deleted = 0

    AND m.category_id = #{categoryId}


    AND m.label_id = #{labelId}


    AND s.subject_name LIKE CONCAT('%', #{keyword}, '%')

SELECT DISTINCT s.id FROM subject s INNER JOIN subject_mapping m ON s.id = m.subject_id AND m.is_deleted = 0 WHERE s.is_deleted = 0 AND m.label_id IN
#{labelId}
ORDER BY RAND() LIMIT #{limit}
